        costPerLead: campaign.custom_metrics?.cost_per_lead || 0,
        messages: campaign.custom_metrics?.messages || 0,
        costPerMessage: campaign.custom_metrics?.cost_per_message || 0,
        roas: campaign.custom_metrics?.roas || 0,
